mapper.sql:
WHERE h.region_code = #{regionCode}

    AND h.house_type = #{houseType}


    AND ld.deal_type = #{dealType}


    AND COALESCE(ld.deal_amount, ld.deposit_amount, 0) >= #{minAmount}


    AND COALESCE(ld.deal_amount, ld.deposit_amount, 0) <= #{maxAmount}

mapper.select:
SELECT EXISTS(
    SELECT 1
    FROM region_code
    WHERE region_code = #{regionCode}
)

SELECT h.house_id AS houseId, h.apt_name AS aptName, h.jibun AS jibun, h.build_year AS buildYear, h.house_type AS houseType, ld.deal_type AS latestDealType, ld.deal_amount AS latestDealAmount, ld.deposit_amount AS latestDepositAmount, ld.monthly_rent AS latestMonthlyRent, ld.deal_date AS latestDealDate, ld.area AS latestArea, ld.floor AS latestFloor FROM house h INNER JOIN (
) ld ON ld.house_id = h.house_id AND ld.rn = 1
ORDER BY ld.deal_date DESC, h.house_id DESC LIMIT #{size} OFFSET #{offset}
